-- ===================================================================
-- 360 Performance — import of the two source workbooks.
--   A) 360_performance_inventory_v1.xlsx        (house inventory)
--   B) 360 Performance - Investor Item Tracking.xlsx (investor deal)
-- Costs are PKR; POs use frozen_rate_rmb_pkr = 1.0 so
--   landed = unit_cost_rmb*rate + shipping + packaging  reproduces the sheet exactly.
-- ===================================================================
begin;
set local request.jwt.claims = '{"sub":"df7da8d2-4387-40dd-85a0-027f77976805","role":"authenticated"}';

-- ---- 1. clear demo/seed transactional data (categories, users, settings kept)
delete from stock_movements;
delete from batches;
delete from customer_deliveries;
delete from corrections;
delete from refunds;
delete from payments;
delete from invoice_items;
delete from invoices;
delete from order_stage_events;
delete from order_items;
delete from build_lines;
delete from builds;
delete from orders;
delete from vendor_advance_entries;
delete from investor_payouts;
delete from purchase_order_lines;
delete from purchase_orders;
delete from pr_gifts;
delete from planned_purchases;
delete from cash_marketing;
delete from expenses;
delete from products;
delete from investor_deals;
delete from investors;
delete from customers;
delete from suppliers;
delete from audit_log;
delete from sku_sequences;

-- ---- 2. suppliers (Chinese vendors; a trigger auto-creates each one's vendor_account)
-- some costing rows name no vendor; park their POs on a placeholder so supplier_id stays NOT NULL

-- ---- 3. investor + deal (Farhan, 50/50 profit split)
  select id, 0.5000, 'Batch 1 — BMW/JZX parts (50/50)', true from investors where name='Farhan';

-- ---- 4. products
--   house = the internal-costing sheet; investor = the investor workbook.

-- ---- 5. purchase orders + lines (one PO per vendor per source sheet)
--   unit_cost_rmb carries the sheet's PKR unit cost; frozen rate 1.0 (sheets hold no RMB).


-- ---- 6. receive stock (RPC: creates the batch + 'receive' movement at landed cost)
--   house: all lines received (goods owned; see import notes)
--   investor: only rows the sheet marks 'Received'; 'China to Pak' stays in transit
